using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns JsonTypeInfo<T> directly, no cast needed
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded → {found!.Type.Name}");
}

// Now demonstrate the "not available" path.
// Build options with a source-gen context that only knows about Person.
var restricted = new JsonSerializerOptions { TypeInfoResolver = SmallContext.Default };

if (restricted.TryGetTypeInfo<Person>(out _))
    Console.WriteLine("TryGetTypeInfo<Person> on restricted → found");
else
    Console.WriteLine("TryGetTypeInfo<Person> on restricted → NOT found");

// Order is *not* in the resolver, so this should return false
if (restricted.TryGetTypeInfo<Order>(out _))
    Console.WriteLine("TryGetTypeInfo<Order>  on restricted → found");
else
    Console.WriteLine("TryGetTypeInfo<Order>  on restricted → NOT found (no exception!)");

// --- Types -----------------------------------------------------------
public record Person(string Name, int Age);
public record Order(int Id, decimal Total);

// Source-gen context that only resolves Person
[JsonSerializable(typeof(Person))]
public partial class SmallContext : JsonSerializerContext;

